class Solution2 {
public:
    int minDeletionSize(vector<string>& A) {
        int result = 0;
        vector<bool> is_sorted(A.size() - 1);
        for (int j = 0; j < A[0].size(); ++j) {
            vector<bool> tmp(is_sorted);
            int i = 0;
            for (; i < A.size() - 1; ++i) {
                if (A[i][j] > A[i + 1][j] && tmp[i] == false) {
                    ++result;
                    break;
                }
                if (A[i][j] < A[i + 1][j]) {
                    tmp[i] = true;
                }
            }
            if (i == A.size() - 1) {
                is_sorted = move(tmp);
            }
        }
        return result;
    }
};

# Time:  O(n * l)
# Space: O(n)

class Solution(object):
    def minDeletionSize(self, A):
        """
        :type A: List[str]
        :rtype: int
        """
        result = 0
        unsorted = set(range(len(A)-1))
        for j in xrange(len(A[0])):
            if any(A[i][j] > A[i+1][j] for i in unsorted):
                result += 1
            else:
                unsorted -= set(i for i in unsorted if A[i][j] < A[i+1][j])
        return result


